    <script>
    (function(){
        function applyTheme(t){
            var w=document.querySelector('.W');
            if(!w)return;
            w.setAttribute('data-theme',t);var dots=document.querySelectorAll('.H-d');
            for(var i=0;i<dots.length;i++){
                if(dots[i].getAttribute('data-t')===t){dots[i].classList.add('on');}
                else{dots[i].classList.remove('on');}
            }try{localStorage.setItem('qqgw_theme',t);}catch(e){}
        }

        function toggleCollapse(){
            var w=document.querySelector('.W');
            if(!w)return;
            var b=w.querySelector('.B'),f=w.querySelector('.F');
            if(!b||!f)return;
            if(b.style.display==='none'){b.style.display='grid';f.style.display='flex';}
            else{b.style.display='none';f.style.display='none';}
        }

        function sendCmd(text){
            try{
                var el=parent.document.getElementById('send_textarea');
                if(el){var v=el.value||'';el.value=v+(v&&!v.endsWith('\n')?'\n':'')+text;el.focus();el.dispatchEvent(new Event('input',{bubbles:true}));}
            }catch(e){}
        }

        function bindAll(){
            var saved='void';
            try{saved=localStorage.getItem('qqgw_theme')||'void';}catch(e){}
            applyTheme(saved);

            document.addEventListener('click',function(e){
                var dot=e.target.closest?e.target.closest('.H-d'):null;
                if(!dot&&e.target.classList&&e.target.classList.contains('H-d'))dot=e.target;
                if(dot){var t=dot.getAttribute('data-t');if(t)applyTheme(t);return;}

                var ava=e.target.closest?e.target.closest('.H-ava'):null;
                if(!ava&&e.target.classList&&e.target.classList.contains('H-ava'))ava=e.target;
                if(ava){toggleCollapse();return;}

                var add=e.target.closest?e.target.closest('.AT-add'):null;
                if(!add&&e.target.classList&&e.target.classList.contains('AT-add'))add=e.target;
                if(add){
                    var stat=add.getAttribute('data-stat');
                    if(stat)sendCmd('（系统指令：消耗1点未分配属性点，提升【'+stat+'】。请描写属性提升感受并输出变量更新）');
                    return;
                }

                var use=e.target.closest?e.target.closest('.BAG-use'):null;
                if(!use&&e.target.classList&&e.target.classList.contains('BAG-use'))use=e.target;
                if(use){
                    var item=use.getAttribute('data-item');
                    if(item)sendCmd('（系统指令：我使用了背包中的【'+item+'】。请描写使用效果，扣除该物品数量1个（数量为0则移除），并输出变量更新）');
                    return;
                }

                var sm=e.target.closest?e.target.closest('.SM-btn'):null;
                if(!sm&&e.target.classList&&e.target.classList.contains('SM-btn'))sm=e.target;
                if(sm){
                    var nm=sm.getAttribute('data-summon');
                    if(nm)sendCmd('（系统指令：我对召唤物/契约体【'+nm+'】下达指令。请描写它的行动并输出变量更新）');
                    return;
                }
            });
        }

        if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',bindAll);}
        else{bindAll();}
    })();
    </script>

    <script type="module">
        function g(p,d){try{return _.get(getAllVariables(),'stat_data.'+p,d);}catch(e){return d;}}

        function isUsable(name){
            var keys=['药','丹','水','卷轴','符','瓶','食','饮','膏','散','丸','剂','包扎','绷带','解毒','回复','治疗','补给'];
            return keys.some(function(k){return name.includes(k);});
        }

        function r(){
            try{
                $('.H-name').text(g('user.姓名','{{user}}'));
                $('.H-lv').text('Lv.'+g('user.等级',1));
                $('.H-job').text(g('user.职业','未觉醒'));
                $('.H-state').text(g('user.当前状态','正常'));
                var pts=Number(g('user.未分配属性点',0))||0;$('.H-pts-v').text(pts);
                if(pts>0){$('.AT-add').css('display','block');$('.H-pts').show();}
                else{$('.AT-add').css('display','none');$('.H-pts').hide();}

                var ufav=Number(g('user.好感度',0))||0;
                $('.H-fav-fl').css('width',Math.min(Math.max(ufav,-100),100)/100*50+50+'%');
                $('.H-fav-n').text(ufav);

                var exp=Number(g('user.当前经验值',0))||0;
                exp=Math.min(Math.max(exp,0),100);
                $('.H-exp-fl').css('width',exp+'%');
                $('.H-exp-n').text(exp+'%');

                var st={str:g('user.力量',0),agi:g('user.敏捷',0),con:g('user.体质',0),spi:g('user.精神',0)};
                $.each(st,function(k,v){$('.v-'+k).text(v);$('.f-'+k).css('width',Math.min(v/200*100,100)+'%');});

                $('.MY-txt').text(g('user.内心想法','...'));

