        .sec-title{font-size:clamp(0.82rem,2vw,0.95rem);color:var(--pri);font-weight:900;letter-spacing:1px;margin-bottom:14px;text-shadow:0 0 12px var(--glow),0 1px 3px rgba(0,0,0,0.5);}
        .lbl{font-size:clamp(0.7rem,1.5vw,0.78rem);color:var(--muted);margin-bottom:6px;display:block;font-weight:700;text-shadow:0 1px 3px rgba(0,0,0,0.5);}

        .dual-grid{display:grid;grid-template-columns:1fr 1fr;gap:clamp(8px,2vw,14px);}
        .dual-card{padding:clamp(14px,3vw,24px) clamp(10px,2vw,16px);border-radius:16px;text-align:center;cursor:pointer;border:1px solid rgba(255,255,255,0.1);background:var(--card);transition:all 0.35s;}
        .dual-card:hover{border-color:var(--pri);background:rgba(255,255,255,0.06);transform:translateY(-3px);}
        .dual-card.active{border-color:var(--pri2);background:rgba(255,255,255,0.09);box-shadow:0 0 25px var(--glow);}
        .dual-icon{font-size:clamp(1.6rem,4vw,2.4rem);margin-bottom:8px;transition:transform 0.3s;}
        .dual-card.active .dual-icon{transform:scale(1.12);}
        .dual-name{font-weight:900;font-size:clamp(0.82rem,2vw,1rem);color:var(--text);text-shadow:0 1px 4px rgba(0,0,0,0.5);}
        .dual-desc{font-size:clamp(0.6rem,1.4vw,0.7rem);color:var(--muted);margin-top:6px;line-height:1.55;text-shadow:0 1px 3px rgba(0,0,0,0.5);}

        .gender-row{display:flex;gap:clamp(6px,1.5vw,12px);margin:7px 0;}
        .gender-card{flex:1;padding:clamp(8px,2vw,14px) 6px;border-radius:12px;text-align:center;cursor:pointer;border:1px solid rgba(255,255,255,0.1);background:var(--card);transition:all 0.3s;}
        .gender-card:hover{border-color:var(--pri);transform:translateY(-2px);}
        .gender-card.active{border-color:var(--pri2);background:rgba(255,255,255,0.09);box-shadow:0 0 16px var(--glow);}
        .gender-icon{font-size:clamp(1.3rem,3vw,1.8rem);margin-bottom:4px;}
        .gender-name{font-size:clamp(0.72rem,1.6vw,0.84rem);font-weight:900;color:var(--text);text-shadow:0 1px 3px rgba(0,0,0,0.5);}

        .inp{width:100%;padding:clamp(8px,1.8vw,12px) clamp(10px,2vw,15px);border-radius:12px;font-size:clamp(0.8rem,1.8vw,0.9rem);background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.16);color:var(--text);font-family:var(--font);text-shadow:0 1px 2px rgba(0,0,0,0.4);transition:all 0.3s;}
        .inp:focus{border-color:var(--pri);box-shadow:0 0 12px var(--glow);background:rgba(255,255,255,0.12);}
        .inp::placeholder{color:rgba(200,200,220,0.38);}

        .tags{display:flex;flex-wrap:wrap;gap:clamp(5px,1.2vw,8px);margin:7px 0;}
        .tag{padding:clamp(5px,1vw,7px) clamp(10px,2vw,16px);border-radius:22px;font-size:clamp(0.68rem,1.5vw,0.76rem);cursor:pointer;background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.13);color:var(--muted);transition:all 0.25s;text-shadow:0 1px 3px rgba(0,0,0,0.5);}
        .tag:hover{background:rgba(255,255,255,0.11);color:var(--text);border-color:var(--pri);transform:scale(1.05);}
        .tag.active{background:var(--pri2);color:#fff;border-color:var(--pri2);box-shadow:0 0 10px var(--glow);text-shadow:0 0 6px rgba(0,0,0,0.4);}

        .rank-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:clamp(4px,1vw,7px);}
        .rank-cell{padding:clamp(8px,1.8vw,12px) 3px;border-radius:12px;text-align:center;cursor:pointer;border:1px solid rgba(255,255,255,0.1);background:var(--card);transition:all 0.3s;}
        .rank-cell:hover{border-color:var(--pri);transform:translateY(-2px);}
        .rank-cell.active{border-color:var(--acc);background:rgba(255,255,255,0.07);box-shadow:0 0 16px var(--glow2);}
        .rank-val{font-size:clamp(0.88rem,2.2vw,1.1rem);font-weight:900;color:var(--pri);text-shadow:0 0 8px var(--glow),0 1px 2px rgba(0,0,0,0.5);}
        .rank-cell.active .rank-val{color:var(--acc);text-shadow:0 0 10px var(--glow2);}
        .rank-sub{font-size:clamp(0.5rem,1.1vw,0.6rem);color:var(--muted);display:block;margin-top:2px;text-shadow:0 1px 2px rgba(0,0,0,0.5);}

        .rank-hint{margin-top:12px;font-size:clamp(0.6rem,1.3vw,0.68rem);color:var(--muted);line-height:1.75;padding:clamp(7px,1.5vw,11px) clamp(9px,2vw,14px);background:rgba(255,255,255,0.05);border-radius:10px;border:1px solid rgba(255,255,255,0.08);text-shadow:0 1px 2px rgba(0,0,0,0.5);}
        .rank-hint strong{text-shadow:0 0 8px var(--glow);}

        .route-stack{display:flex;flex-direction:column;gap:clamp(6px,1.5vw,10px);}
        .route-card{padding:clamp(10px,2vw,14px) clamp(10px,2vw,16px);border-radius:14px;cursor:pointer;border:1px solid rgba(255,255,255,0.1);background:var(--card);display:flex;align-items:center;gap:clamp(8px,2vw,14px);transition:all 0.3s;}
        .route-card:hover{border-color:var(--pri);transform:translateX(4px);}
        .route-card.active{border-color:var(--acc);background:rgba(255,255,255,0.07);box-shadow:0 0 16px var(--glow2);}
        .route-card.locked{opacity:0.38;cursor:not-allowed;}
        .route-card.locked:hover{transform:none;border-color:rgba(255,255,255,0.1);}
        .route-icon{font-size:clamp(1.2rem,3vw,1.5rem);width:clamp(28px,5vw,36px);text-align:center;flex-shrink:0;}
        .route-name{font-weight:900;font-size:clamp(0.78rem,1.8vw,0.9rem);color:var(--text);text-shadow:0 1px 3px rgba(0,0,0,0.5);}
        .route-desc{font-size:clamp(0.6rem,1.3vw,0.68rem);color:var(--muted);margin-top:2px;text-shadow:0 1px 2px rgba(0,0,0,0.5);}
        .route-req{font-size:clamp(0.54rem,1.1vw,0.62rem);padding:2px 7px;border-radius:8px;margin-left:auto;white-space:nowrap;font-weight:700;flex-shrink:0;}
        .route-req.req-ok{background:rgba(80,210,120,0.18);color:#70ee98;border:1px solid rgba(80,210,120,0.36);text-shadow:0 0 5px rgba(80,210,120,0.5);}
        .route-req.req-lock{background:rgba(255,80,80,0.15);color:#ffaaaa;border:1px solid rgba(255,80,80,0.3);}
        .route-req.req-free{background:rgba(255,255,255,0.06);color:var(--muted);border:1px solid rgba(255,255,255,0.1);}

        .route-hint-box{display:none;margin-top:12px;padding:clamp(10px,2vw,14px) clamp(12px,2.5vw,16px);border-radius:12px;background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.13);font-size:clamp(0.63rem,1.4vw,0.72rem);color:var(--muted);line-height:1.95;white-space:pre-line;animation:panelFade 0.3s ease;text-shadow:0 1px 2px rgba(0,0,0,0.5);}

        #routeNotice{font-size:clamp(0.64rem,1.4vw,0.72rem);color:var(--muted);margin-bottom:9px;padding:6px 10px;background:rgba(255,255,255,0.05);border-radius:8px;border:1px solid rgba(255,255,255,0.08);text-shadow:0 1px 2px rgba(0,0,0,0.5);}

        .custom-bg-panel{margin-top:10px;padding:clamp(9px,2vw,14px);border-radius:12px;background:rgba(255,255,255,0.05);border:1px dashed rgba(255,255,255,0.16);display:none;animation:panelFade 0.35s ease;}
        .custom-bg-panel.show{display:block;}
        .custom-bg-tip{font-size:clamp(0.6rem,1.3vw,0.67rem);color:var(--muted);margin-top:6px;line-height:1.6;text-shadow:0 1px 2px rgba(0,0,0,0.5);}

        .attr-zone{display:flex;flex-direction:column;gap:clamp(9px,2vw,13px);}
        .attr-row{display:flex;align-items:center;gap:clamp(7px,1.5vw,12px);}
        .attr-name{width:clamp(28px,5vw,40px);font-size:clamp(0.74rem,1.7vw,0.84rem);font-weight:700;color:var(--muted);text-align:right;text-shadow:0 1px 3px rgba(0,0,0,0.5);}
        .attr-slider{flex-grow:1;-webkit-appearance:none;height:5px;border-radius:3px;background:rgba(255,255,255,0.12);outline:none;}
        .attr-slider::-webkit-slider-thumb{-webkit-appearance:none;width:clamp(15px,3vw,19px);height:clamp(15px,3vw,19px);border-radius:50%;background:var(--pri);cursor:pointer;box-shadow:0 0 12px var(--glow);}
        .attr-val{width:clamp(28px,5vw,38px);font-size:clamp(0.88rem,2vw,1rem);font-weight:900;color:var(--acc);text-align:center;text-shadow:0 0 8px var(--glow2),0 1px 2px rgba(0,0,0,0.4);}
        .attr-remain{text-align:center;font-size:clamp(0.72rem,1.6vw,0.82rem);font-weight:700;color:var(--acc);padding:clamp(6px,1.2vw,9px);background:rgba(255,255,255,0.05);border-radius:10px;border:1px solid rgba(255,255,255,0.09);margin-bottom:10px;text-shadow:0 0 8px var(--glow2),0 1px 2px rgba(0,0,0,0.4);}

        .nav-row{display:flex;gap:clamp(7px,1.5vw,12px);margin-top:clamp(12px,2.5vw,18px);}
        .nav-btn{flex:1;padding:clamp(10px,2vw,13px);border:none;border-radius:12px;cursor:pointer;font-size:clamp(0.78rem,1.8vw,0.88rem);font-weight:700;transition:all 0.3s;font-family:var(--font);}
        .nav-btn.prev{background:rgba(255,255,255,0.08);color:var(--muted);border:1px solid rgba(255,255,255,0.14);text-shadow:0 1px 3px rgba(0,0,0,0.5);}
        .nav-btn.prev:hover{background:rgba(255,255,255,0.14);color:var(--text);}
        .nav-btn.next{background:linear-gradient(135deg,var(--pri2),var(--pri));color:#fff;font-weight:900;box-shadow:0 3px 14px var(--glow);text-shadow:0 1px 4px rgba(0,0,0,0.4);}
        .nav-btn.next:hover{transform:translateY(-2px);box-shadow:0 6px 22px var(--glow);}

        .confirm-btn{width:100%;padding:clamp(12px,2.5vw,16px);border:none;border-radius:14px;cursor:pointer;font-size:clamp(0.88rem,2vw,1rem);font-weight:900;letter-spacing:2px;background:linear-gradient(135deg,var(--pri2),var(--acc));color:#ffffff;box-shadow:0 4px 22px var(--glow);transition:all 0.3s;position:relative;overflow:hidden;font-family:var(--font);text-shadow:0 1px 4px rgba(0,0,0,0.35);}
        .confirm-btn:hover{transform:translateY(-2px);box-shadow:0 6px 30px var(--glow);}
        .confirm-btn::after{content:'';position:absolute;top:0;left:-100%;width:60%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.28),transparent);animation:shimmer 3s infinite;}
        @keyframes shimmer{0%{left:-100%;}100%{left:200%;}}

        @media (max-width:480px){
            .theme-bar{gap:4px;}
            .theme-btn{padding:5px 9px;font-size:0.66rem;}
            .dual-grid{gap:8px;}
            .rank-grid{grid-template-columns:repeat(5,1fr);gap:4px;}
            .gender-row{gap:6px;}
            .route-card{padding:10px 10px;gap:8px;}
            .nav-row{gap:7px;}
        }
    </style>
</head>
<body>
    <div class="panel" data-theme="void">
        <div class="tex-layer tex-void"></div>
        <div class="tex-layer tex-cyber"></div>
        <div class="tex-layer tex-emerald"></div>

        <div class="theme-bar">
            <div class="theme-btn active" data-theme="void"><span class="theme-dot"></span>暗紫·星辰</div>
            <div class="theme-btn" data-theme="cyber"><span class="theme-dot"></span>冰蓝·赛博</div>
            <div class="theme-btn" data-theme="emerald"><span class="theme-dot"></span>翡翠·暗金</div>
        </div>

        <div class="crystal-zone">
            <div class="crystal-container">
                <div class="outer-ring"></div>
                <div class="deco-ring ring-void"></div>
                <div class="deco-ring ring-cyber"></div>
                <div class="deco-ring ring-emerald"></div>
                <div class="crystal-orb" id="crystalOrb">
                    <span class="crystal-rank" id="crystalDisp">✦</span>
                </div>
            </div>
            <div class="crystal-title" id="titleText">— 虚空低语 · 命运织锦 —</div>
            <div class="crystal-sub" id="subText">星辰在等待你的回响...</div>
        </div>

        <div class="step-bar">
            <div class="step-dot active" data-step="0"></div><div class="step-conn"></div>
            <div class="step-dot" data-step="1"></div><div class="step-conn"></div>
            <div class="step-dot" data-step="2"></div><div class="step-conn"></div>
            <div class="step-dot" data-step="3"></div><div class="step-conn"></div>
            <div class="step-dot" data-step="4"></div><div class="step-conn"></div>
            <div class="step-dot" data-step="5"></div>
        </div>

        <div class="body">

            <!-- Step 0: 觉醒方式 -->
            <div class="step-panel active" data-step="0">
                <div class="sec-title">✦ 选择你的觉醒方式</div>
                <div class="dual-grid">
                    <div class="dual-card" data-mode="random">
                        <div class="dual-icon">🌌</div>
                        <div class="dual-name">星辰抉择</div>
                        <div class="dual-desc">命运随机降临<br>接受星辰的安排</div>
                    </div>
                    <div class="dual-card" data-mode="custom">
                        <div class="dual-icon">🔮</div>
                        <div class="dual-name">意志铸造</div>
                        <div class="dual-desc">亲手编织命运<br>自定义你的道路</div>
                    </div>
                </div>
                <div class="nav-row">
                    <button class="nav-btn next" id="s0next">继续 <i class="fa-solid fa-chevron-right"></i></button>
                </div>
            </div>

            <!-- Step 1: 角色信息 -->
            <div class="step-panel" data-step="1">
                <div class="sec-title">✦ 铭刻你的灵魂印记</div>
                <label class="lbl">角色姓名 <span style="opacity:0.55;font-weight:400">(留空则使用默认名)</span></label>
                <input class="inp" id="inp-name" placeholder="在此写下你的名字..." maxlength="20">
                <label class="lbl" style="margin-top:13px;">性别</label>
                <div class="gender-row">
                    <div class="gender-card" data-gender="男"><div class="gender-icon">♂</div><div class="gender-name">男</div></div>
                    <div class="gender-card" data-gender="女"><div class="gender-icon">♀</div><div class="gender-name">女</div></div>
                    <div class="gender-card" data-gender="不指定"><div class="gender-icon">✧</div><div class="gender-name">不指定</div></div>
                </div>
                <label class="lbl" style="margin-top:13px;">外貌描述 <span style="opacity:0.55;font-weight:400">(AI将据此描写外形)</span></label>
                <textarea class="inp" id="inp-appearance" style="resize:vertical;min-height:64px;" placeholder="例如：黑色中长发，眼眸深邃，身材修长，左颊有一道淡淡的疤痕..."></textarea>
                <div class="nav-row">
                    <button class="nav-btn prev" data-go="0"><i class="fa-solid fa-chevron-left"></i></button>
                    <button class="nav-btn next" data-go="2">继续 <i class="fa-solid fa-chevron-right"></i></button>
                </div>
            </div>

            <!-- Step 2: 职业 -->
            <div class="step-panel" data-step="2">
                <div class="sec-title">✦ 铭刻你的职业之名</div>
                <label class="lbl">职业名称</label>
                <input class="inp" id="inp-job" placeholder="在此铭刻你的职业..." maxlength="20">
                <label class="lbl" style="margin-top:11px;">战斗定位</label>
                <div class="tags" id="tagGroup">
                    <div class="tag" data-tag="近战">⚔ 近战</div>
                    <div class="tag" data-tag="远程">🏹 远程</div>
                    <div class="tag" data-tag="法术">✨ 法术</div>
                    <div class="tag" data-tag="辅助">💜 辅助</div>
                    <div class="tag" data-tag="召唤">👁 召唤</div>
                    <div class="tag" data-tag="特殊">🔮 特殊</div>
                </div>
                <label class="lbl" style="margin-top:11px;">能力描述 <span style="opacity:0.55;font-weight:400">(选填)</span></label>
                <textarea class="inp" id="inp-desc" style="resize:vertical;min-height:52px;" placeholder="描述你的力量本质与战斗风格..."></textarea>
                <div class="nav-row">
                    <button class="nav-btn prev" data-go="1"><i class="fa-solid fa-chevron-left"></i></button>
                    <button class="nav-btn next" data-go="3">继续 <i class="fa-solid fa-chevron-right"></i></button>
                </div>
            </div>

            <!-- Step 3: 评级 -->
            <div class="step-panel" data-step="3">
                <div class="sec-title">✦ 觉醒共鸣等级</div>
                <div class="rank-grid">
                    <div class="rank-cell" data-rank="F"><span class="rank-val">F</span><span class="rank-sub">微光</span></div>
                    <div class="rank-cell" data-rank="D"><span class="rank-val">D</span><span class="rank-sub">暗星</span></div>
                    <div class="rank-cell" data-rank="C"><span class="rank-val">C</span><span class="rank-sub">星辰</span></div>
                    <div class="rank-cell" data-rank="B"><span class="rank-val">B</span><span class="rank-sub">星座</span></div>
                    <div class="rank-cell" data-rank="A"><span class="rank-val">A</span><span class="rank-sub">星河</span></div>
                    <div class="rank-cell" data-rank="S"><span class="rank-val">S</span><span class="rank-sub">星域</span></div>
                    <div class="rank-cell" data-rank="SS"><span class="rank-val">SS</span><span class="rank-sub">星海</span></div>
                    <div class="rank-cell" data-rank="SSS"><span class="rank-val">SSS</span><span class="rank-sub">创世</span></div>
                    <div class="rank-cell" data-rank="变异废相"><span class="rank-val" style="font-size:clamp(0.6rem,1.3vw,0.74rem)">变异</span><span class="rank-sub">异变</span></div>
                    <div class="rank-cell" data-rank="禁忌法则"><span class="rank-val" style="font-size:clamp(0.6rem,1.3vw,0.74rem)">禁忌</span><span class="rank-sub">深渊</span></div>
                </div>
                <div class="rank-hint">
                    ▸ <strong style="color:var(--pri)">F / D / 变异</strong> → 仅限【深渊逆袭线】<br>
                    ▸ <strong style="color:var(--pri)">C / B</strong> → 限【深渊逆袭线】或自定义<br>
                    ▸ <strong style="color:var(--pri)">A / S</strong> → 限【学院权力线】或自定义<br>
                    ▸ <strong style="color:var(--pri)">SS / SSS / 禁忌</strong> → 限【国家兵器线】或自定义<br>
                    ▸ <strong style="color:var(--pri)">全等级</strong> → 可选【万人之上线】
                </div>
                <div class="nav-row">
                    <button class="nav-btn prev" data-go="2"><i class="fa-solid fa-chevron-left"></i></button>
                    <button class="nav-btn next" data-go="4">继续 <i class="fa-solid fa-chevron-right"></i></button>
                </div>
            </div>

            <!-- Step 4: 路线 -->
            <div class="step-panel" data-step="4">
                <div class="sec-title">✦ 命运的织线</div>
                <div id="routeNotice">💡 请先在上一步选择评级，路线将据此自动解锁</div>
                <div class="route-stack">
                    <div class="route-card" id="route-abyss" data-route="深渊逆袭线">
                        <div class="route-icon">🔥</div>
                        <div style="flex-grow:1"><div class="route-name">深渊逆袭线</div><div class="route-desc">在黑暗中绽放，刀尖上起舞</div></div>
                        <div class="route-req req-free" id="req-abyss">F~D/变异</div>
                    </div>
                    <div class="route-card" id="route-academy" data-route="学院权力线">
                        <div class="route-icon">⚡</div>
                        <div style="flex-grow:1"><div class="route-name">学院权力线</div><div class="route-desc">在权谋中觉醒，棋局中登顶</div></div>
                        <div class="route-req req-free" id="req-academy">A/S 限定</div>
                    </div>
                    <div class="route-card" id="route-nation" data-route="国家兵器线">
                        <div class="route-icon">🛡️</div>
                        <div style="flex-grow:1"><div class="route-name">国家兵器线</div><div class="route-desc">在战场上淬炼，铁血中铸魂</div></div>
                        <div class="route-req req-free" id="req-nation">SS+/禁忌</div>
                    </div>
                    <div class="route-card" id="route-apex" data-route="万人之上线">
                        <div class="route-icon">👑</div>
                        <div style="flex-grow:1"><div class="route-name">万人之上线【建议三条线路玩完 最后游玩此线路 不然您会对此卡失去兴趣】</div><div class="route-desc">跳过挣扎，直接站在最顶上</div></div>
                        <div class="route-req req-free" id="req-apex">全等级 / 18+</div>
                    </div>
                    <div class="route-card" id="route-custom" data-route="custom">
                        <div class="route-icon">🌀</div>
                        <div style="flex-grow:1"><div class="route-name">自定义模式</div><div class="route-desc">亲手书写开局，定制专属故事</div></div>
                        <div class="route-req req-free" id="req-custom">全等级</div>
