                <div class="nav-row">
                    <button class="nav-btn prev" data-go="3"><i class="fa-solid fa-chevron-left"></i></button>
                    <button class="nav-btn next" data-go="5">继续 <i class="fa-solid fa-chevron-right"></i></button>
