            </div>

            <!-- Step 5: 属性 + 确认 -->
            <div class="step-panel" data-step="5">
                <div class="sec-title">✦ 注入灵魂参数</div>
                <div class="attr-remain">星尘余量：<strong id="attrRem">200</strong> / 200</div>
                <div class="attr-zone">
                    <div class="attr-row"><span class="attr-name">力量</span><input type="range" class="attr-slider" data-stat="str" min="10" max="150" value="50"><span class="attr-val" id="v-str">50</span></div>
                    <div class="attr-row"><span class="attr-name">敏捷</span><input type="range" class="attr-slider" data-stat="agi" min="10" max="150" value="50"><span class="attr-val" id="v-agi">50</span></div>
                    <div class="attr-row"><span class="attr-name">体质</span><input type="range" class="attr-slider" data-stat="con" min="10" max="150" value="50"><span class="attr-val" id="v-con">50</span></div>
                    <div class="attr-row"><span class="attr-name">精神</span><input type="range" class="attr-slider" data-stat="spi" min="10" max="150" value="50"><span class="attr-val" id="v-spi">50</span></div>
