                    </button>
                </div>
            </div>

        </div>
    </div>

    <script>
    (function(){
        var CHAR_BG = '【角色固定背景设定，必须严格遵守】身形清瘦但匀称，蕴含着猎豹般的爆发力。校服总是穿得松松垮垮，领口的扣子从不扣到顶，露出底下一点银色链子的反光。黑色短发有些凌乱，几缕碎发搭在额前，遮不住那双深邃的眼眸。平时总是半眯着，透着一股慵懒和漫不经心，但偶尔闪过的锐利精光，会暴露他远超同龄人的警觉。左边眉尾有一道很浅的疤痕，是某次街头斗殴留下的纪念品，反而给他增添了几分不羁的野性。表面上是个对什么都无所谓的"不良"，上课睡觉，不参与任何集体活动，在班级里像个透明人。但这种疏离感是他刻意维持的保护色。实际上，他心思缜密，观察力敏锐，信奉"人不犯我我不犯人"的街头准则。他内心深处隐藏着强烈的自尊和对未来的渴望，只是从不宣之于口。对于即将到来的觉醒仪式，他比任何人都更紧张，也更期待，因为这是他摆脱底层命运的唯一机会。来自下城区的孤儿，为了生计做过各种兼职，早已尝遍生活艰辛。觉醒前没有任何超凡能力，但是个天生的街头斗士，身手敏捷，反应神速，拥有极高的痛觉忍耐度和钢铁般的意志力。';

        var RANK_ROUTES = {
            'F':['深渊逆袭线','万人之上线','custom'],
            'D':['深渊逆袭线','万人之上线','custom'],
            'C':['深渊逆袭线','万人之上线','custom'],
            'B':['深渊逆袭线','万人之上线','custom'],
            'A':['学院权力线','万人之上线','custom'],
            'S':['学院权力线','万人之上线','custom'],
            'SS':['国家兵器线','万人之上线','custom'],
            'SSS':['国家兵器线','万人之上线','custom'],
            '变异废相':['深渊逆袭线','万人之上线','custom'],
            '禁忌法则':['国家兵器线','万人之上线','custom']
        };

        var ROUTE_HINT = {
            '深渊逆袭线':
                '🔥  深渊逆袭线\n' +
                '这条路线设有 4 个专属里程碑高潮剧情，将在你游玩过程中自然触发。\n' +
                '每个里程碑都隐藏着能永久改变羁绊走向的关键抉择——现在告诉你会破坏那种被命运砸中的冲击感。\n' +
                '只管自由游玩，当时机到来时，故事自己会把你推向那一刻。',
            '学院权力线':
                '⚡  学院权力线\n' +
                '这条路线设有 4 个专属里程碑高潮剧情，将在你游玩过程中自然触发。\n' +
                '权力、背叛、生死之间的抉择贯穿始终——但现在告诉你会破坏那种被命运砸中的冲击感。\n' +
                '只管自由游玩，当时机到来时，故事自己会把你推向那一刻。',
            '国家兵器线':
                '🛡️  国家兵器线\n' +
                '这条路线设有 4 个专属里程碑高潮剧情，将在你游玩过程中自然触发。\n' +
                '每一个都是城区级别的战场事件，每次抉择都将永久改变你与核心人物之间的关系。\n' +
                '只管自由游玩，当时机到来时，故事自己会把你推向那一刻。',
            '万人之上线':
                '👑  万人之上线  ⚠️ 18+\n\n' +
                '这条线没有觉醒仪式，没有废相嘲讽，没有从底层往上爬的过程。\n' +
                '你直接从终点开始。\n\n' +
                '白氏家族已覆灭。联邦议会重新洗牌，世家们递来的拜帖摞了半张桌子。\n' +
                '上城区的悬浮花园里，所有人开会前第一件事是确认你今天的心情。\n\n' +
                '苏璃把烟斗放在你面前，第一次站在你身边而不是对面。\n' +
                '她的情报网是你的眼睛。她爱你这件事，是她唯一没有用来换过利益的东西。\n\n' +
                '夏语冰还穿着那件风纪外套，但风纪委的命令现在要经过你才能生效。\n' +
                '她为这个别扭了很久。接受的理由她从来不说出口。\n\n' +
                '林夜从前线回来第一件事是来找你，不是因为军规。\n' +
                '她管你叫什么只有你们两个知道，不是指挥官，也不是军衔。\n\n' +
                '叶轻舞把整个叶氏情报网的钥匙放在你手里，\n' +
                '说这是她押过最准的一注。她靠得很近，但眼睛在看你今晚的心情。\n\n' +
                '四个人，好感度全满，全部臣服，各有各的爱法，各有各的别扭。\n' +
                '不限职业，不限等级。外面还有想挑战新秩序的势力，你可以理会，也可以不管。\n' +
                '这条线只有一件事：你已经赢了，现在享受就行了。',
            'custom': ''
        };

        var mode='',rank='',route='',jobType='',gender='',curStep=0;
        var st={str:50,agi:50,con:50,spi:50},TOTAL=200;

        var themeText={
            void:{title:'— 虚空低语 · 命运织锦 —',sub:'星辰在等待你的回响...',sym:'✦'},
            cyber:{title:'◆ NEURAL LINK · 源启共鸣 ◆',sub:'Initializing awakening protocol...',sym:'◆'},
            emerald:{title:'⟐ 源古圣匣 · 觉醒铭文 ⟐',sub:'远古之力在沉睡中等待你的触碰...',sym:'⟐'}
        };

        function autoSend(text){
            var el=parent.document.getElementById('send_textarea');
            if(el){
                el.value=text;el.focus();
                el.dispatchEvent(new Event('input',{bubbles:true}));
                setTimeout(function(){
                    var btn=parent.document.getElementById('send_but');
                    if(btn)btn.click();
                },150);
            }else{alert('指令：\n'+text);}
        }

        document.querySelectorAll('.theme-btn').forEach(function(btn){
            btn.addEventListener('click',function(){
                var t=this.dataset.theme;
                document.querySelector('.panel').setAttribute('data-theme',t);
                document.querySelectorAll('.theme-btn').forEach(function(b){b.classList.remove('active');});
                this.classList.add('active');
                document.getElementById('titleText').textContent=themeText[t].title;
                document.getElementById('subText').textContent=themeText[t].sub;
                if(!document.getElementById('crystalOrb').classList.contains('has-rank'))
                    document.getElementById('crystalDisp').textContent=themeText[t].sym;
            });
        });

        function goStep(n){
            curStep=n;
            document.querySelectorAll('.step-panel').forEach(function(p){p.classList.toggle('active',+p.dataset.step===n);});
            document.querySelectorAll('.step-dot').forEach(function(d){
                d.classList.remove('active');
                if(+d.dataset.step===n)d.classList.add('active');
            });
            if(n===4)updateRouteLock();
        }

        function updateRouteLock(){
            var allowed=rank?(RANK_ROUTES[rank]||['custom']):[];
            var cards={
                'route-abyss':'深渊逆袭线',
                'route-academy':'学院权力线',
                'route-nation':'国家兵器线',
                'route-apex':'万人之上线',
                'route-custom':'custom'
            };
            var lockTxt={
                'route-abyss':'✗ 需F~D/变异',
                'route-academy':'✗ 需A/S级',
                'route-nation':'✗ 需SS+/禁忌',
                'route-apex':'✓ 全等级',
                'route-custom':'✓ 全等级'
            };
            Object.keys(cards).forEach(function(id){
                var card=document.getElementById(id);
                var req=document.getElementById(id.replace('route-','req-'));
                var val=cards[id];
                var isOk=allowed.length===0||allowed.indexOf(val)!==-1;
                if(!rank){
                    card.classList.remove('locked','active');
                    req.className='route-req req-free';
                }else if(isOk){
                    card.classList.remove('locked');
                    req.className='route-req req-ok';
                    if(id==='route-apex'){req.textContent='✓ 全等级 / 18+';}
                    else if(id==='route-custom'){req.textContent='✓ 全等级';}
                    else{req.textContent='✓ 可选';}
                }else{
                    card.classList.add('locked');
                    if(route===val){route='';card.classList.remove('active');}
                    req.className='route-req req-lock';
                    req.textContent=lockTxt[id];
                }
            });
            document.getElementById('routeNotice').style.display=rank?'none':'block';
        }

        document.querySelectorAll('.dual-card').forEach(function(c){
            c.addEventListener('click',function(){
                document.querySelectorAll('.dual-card').forEach(function(x){x.classList.remove('active');});
                this.classList.add('active');mode=this.dataset.mode;
            });
        });

        document.getElementById('s0next').addEventListener('click',function(){
            if(!mode){alert('请选择觉醒方式');return;}
            if(mode==='random'){
                autoSend(CHAR_BG+'\n\n（觉醒仪式启动！我选择【命运轮盘】模式，请严格依照以上角色背景设定，随机决定我的职业与评级，开始描写觉醒仪式！）');
                return;
            }
            goStep(1);
        });

        document.querySelectorAll('.gender-card').forEach(function(c){
            c.addEventListener('click',function(){
                document.querySelectorAll('.gender-card').forEach(function(x){x.classList.remove('active');});
                this.classList.add('active');gender=this.dataset.gender;
            });
        });

        document.querySelectorAll('#tagGroup .tag').forEach(function(t){
            t.addEventListener('click',function(){
                document.querySelectorAll('#tagGroup .tag').forEach(function(x){x.classList.remove('active');});
                this.classList.add('active');jobType=this.dataset.tag;
            });
        });

        document.querySelectorAll('.rank-cell').forEach(function(c){
            c.addEventListener('click',function(){
                document.querySelectorAll('.rank-cell').forEach(function(x){x.classList.remove('active');});
                this.classList.add('active');rank=this.dataset.rank;
                document.getElementById('crystalDisp').textContent=rank;
                document.getElementById('crystalOrb').classList.add('has-rank');
            });
        });

        document.querySelectorAll('.route-card').forEach(function(c){
            c.addEventListener('click',function(){
                if(this.classList.contains('locked')){alert('当前评级【'+rank+'】无法进入此路线！');return;}
                document.querySelectorAll('.route-card').forEach(function(x){x.classList.remove('active');});
                this.classList.add('active');
                route=this.dataset.route;

                var hintBox=document.getElementById('routeHintBox');
                var hintText=ROUTE_HINT[route]||'';
                if(hintText){
                    hintBox.textContent=hintText;
                    hintBox.style.display='block';
                }else{
                    hintBox.style.display='none';
                }

                var bg=document.getElementById('customBgPanel');
                if(route==='custom')bg.classList.add('show');
                else bg.classList.remove('show');
            });
        });

        document.querySelectorAll('.attr-slider').forEach(function(s){
            s.addEventListener('input',function(){
                var k=this.dataset.stat,v=+this.value;
                var oth=Object.keys(st).filter(function(x){return x!==k;}).reduce(function(a,x){return a+st[x];},0);
                if(oth+v>TOTAL){this.value=TOTAL-oth;st[k]=TOTAL-oth;}
                else{st[k]=v;}
                document.getElementById('v-'+k).textContent=st[k];
                document.getElementById('attrRem').textContent=TOTAL-Object.values(st).reduce(function(a,b){return a+b;},0);
            });
        });

        document.querySelectorAll('.nav-btn[data-go]').forEach(function(b){
            b.addEventListener('click',function(){goStep(+this.dataset.go);});
        });

        document.getElementById('confirmBtn').addEventListener('click',function(){
            if(!rank){alert('请选择觉醒评级！');return;}
            if(!route){alert('请选择命运路线！');return;}
            var playerName=document.getElementById('inp-name').value.trim()||'（默认）';
            var appearance=document.getElementById('inp-appearance').value.trim()||'（不指定）';
            var jn=document.getElementById('inp-job').value.trim()||'未指定';
            var jd=document.getElementById('inp-desc').value.trim()||'无';
            var prompt='';

            if(route==='万人之上线'){
                prompt=
                    '（【最高优先级强制覆盖指令】以下设定完全覆盖系统默认值，全程必须严格执行：\n'+
                    '- 玩家角色的【唯一正式名字】：'+playerName+'\n'+
                    '- 玩家角色的【性别】：'+(gender||'不指定')+'\n'+
                    '- 玩家角色的【外貌，全程据此描写，禁止自行添加或修改】：'+appearance+'\n'+
                    '- 职业名称：'+jn+'\n'+
                    '- 职业定位：'+(jobType||'未指定')+'\n'+
                    '- 职业描述：'+jd+'\n'+
                    '- 觉醒评级：'+rank+'\n'+
                    '- 起始路线：万人之上线\n'+
                    '- 初始属性：力量'+st.str+'/敏捷'+st.agi+'/体质'+st.con+'/精神'+st.spi+'\n\n'+
                    '【强制指令】激活万人之上线。跳过觉醒仪式，直接以以下背景开局：\n'+
                    '白氏家族已覆灭，联邦议会重新洗牌，整座城市的权力中心是你。'+
                    '苏璃、夏语冰、林夜、叶轻舞四人好感度全部初始化为100，心理底色为臣服且爱你。'+
                    '请以这个背景开始第一段剧情描写，展示这个世界的当前状态和四位女性各自的初始姿态，18+内容全面开放。）';
                autoSend(prompt);
                return;
            }

            var routeName=route,customBgLine='',bgPrefix='';
            var routeKeyword='';
            if(route==='custom'){
                routeName='自定义模式';
                if(['F','D','C','B','变异废相'].indexOf(rank)!==-1){
                    routeKeyword='\n（当前路线参考：深渊逆袭线）';
                }else if(['A','S'].indexOf(rank)!==-1){
                    routeKeyword='\n（当前路线参考：学院权力线）';
                }else if(['SS','SSS','禁忌法则'].indexOf(rank)!==-1){
                    routeKeyword='\n（当前路线参考：国家兵器线）';
                }
                var bgVal=document.getElementById('inp-custombg').value.trim();
                customBgLine=bgVal
                    ?'\n\n【强制指令】请跳过觉醒仪式，直接以下方自定义场景作为第一段开局内容展开叙述：\n「'+bgVal+'」'
                    :'\n\n【强制指令】路线为自定义模式，请跳过觉醒仪式，自由发挥一个契合职业与评级的开局场景。';
            }else{
                bgPrefix=CHAR_BG+'\n\n';
            }

            prompt=bgPrefix+
                '（【最高优先级强制覆盖指令】以下设定完全覆盖系统默认值，全程必须严格执行，禁止使用任何其他名字或外貌描述：\n'+
                '- 玩家角色的【唯一正式名字】：'+playerName+'（禁止使用{{user}}或任何其他称呼，全程只能叫此名字）\n'+
                '- 玩家角色的【性别】：'+(gender||'不指定')+'（必须按此性别使用对应人称代词）\n'+
                '- 玩家角色的【外貌，全程据此描写，禁止自行添加或修改】：'+appearance+'\n'+
                '- 职业名称：'+jn+'\n'+
                '- 职业定位：'+(jobType||'未指定')+'\n'+
                '- 职业描述：'+jd+'\n'+
                '- 觉醒评级：'+rank+'\n'+
                '- 起始路线：'+routeName+'\n'+
                routeKeyword+
                '- 初始属性：力量'+st.str+'/敏捷'+st.agi+'/体质'+st.con+'/精神'+st.spi+'\n'+
                '请根据以上配置开始觉醒仪式，赋予3个契合职业的初始技能！）'+
                customBgLine;

            autoSend(prompt);
        });
    })();
    </script>
</body>
