        [data-theme="frost"]{--p:#7c8db5;--p2:#5a6e96;--a:#4a6fa5;--g:rgba(90,110,150,.2);--g2:rgba(74,111,165,.15);--bg:rgba(248,250,252,.96);--c1:rgba(241,245,249,.8);--c2:rgba(226,232,240,.6);--bd:rgba(120,140,170,.25);--t:#1a2744;--t2:#364b6e;--m:#5a6e8a;--btn-t:#ffffff;}
        [data-theme="obsidian"]{--p:#8b95a5;--p2:#6b7585;--a:#d1d5db;--g:rgba(107,114,128,.2);--g2:rgba(209,213,219,.15);--bg:rgba(3,3,6,.97);--c1:rgba(12,12,18,.8);--c2:rgba(8,8,12,.6);--bd:rgba(75,85,99,.15);--t:#e5e7eb;--t2:#b0b5bf;--m:#8b919d;--btn-t:#e5e7eb;}
        [data-theme="crimson"]{--p:#f87171;--p2:#dc2626;--a:#fbbf24;--g:rgba(248,113,113,.3);--g2:rgba(251,191,36,.25);--bg:rgba(12,4,4,.96);--c1:rgba(30,8,8,.7);--c2:rgba(20,6,6,.5);--bd:rgba(248,113,113,.12);--t:#fee2e2;--t2:#fca5a5;--m:#c08080;--btn-t:#1a0505;}

        *{box-sizing:border-box;margin:0;padding:0;user-select:none;outline:none;}
        body{font-family:"Noto Sans SC",system-ui,sans-serif;background:transparent;color:var(--t);padding:6px;}

        .W{max-width:780px;margin:0 auto;background:var(--bg);border:1px solid var(--bd);border-radius:14px;box-shadow:0 0 30px var(--g),0 8px 24px rgba(0,0,0,.5);overflow:hidden;position:relative;transition:all .5s;}

        /* ========== HEADER ========== */
        .H{display:flex;align-items:center;padding:12px 14px;gap:10px;border-bottom:1px solid var(--bd);position:relative;z-index:2;background:linear-gradient(135deg,var(--c1),transparent);flex-wrap:wrap;}
        .H-ava{width:46px;height:46px;border-radius:12px;background-size:cover;background-position:center;background-color:#111;border:1.5px solid var(--p);box-shadow:0 0 10px var(--g);flex-shrink:0;cursor:pointer;transition:all .3s;}
        .H-ava:hover{transform:scale(1.08);box-shadow:0 0 18px var(--g);}
        .H-info{flex-grow:1;min-width:0;}
        .H-name{font-size:1rem;font-weight:800;letter-spacing:.5px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}
        .H-tags{display:flex;gap:5px;align-items:center;margin-top:3px;flex-wrap:wrap;}
        .H-lv{background:var(--p);color:var(--btn-t);padding:1px 7px;border-radius:6px;font-size:.64rem;font-weight:800;line-height:1.7;}
        .H-job{font-size:.72rem;color:var(--a);font-weight:700;}
        [data-theme="frost"] .H-job{color:var(--p2);}
        .H-state{font-size:.66rem;color:var(--p);padding:1px 6px;border:1px solid var(--bd);border-radius:5px;font-weight:600;}
        .H-pts{font-size:.64rem;color:var(--a);background:var(--c2);padding:2px 7px;border-radius:5px;display:none;font-weight:600;}

        .H-fav-row{display:flex;align-items:center;gap:5px;margin-top:3px;}
        .H-fav-lbl{font-size:.54rem;color:var(--m);white-space:nowrap;letter-spacing:.5px;font-weight:600;}
        .H-fav-tr{flex-grow:1;height:3px;background:rgba(128,128,128,.12);border-radius:2px;overflow:hidden;}
        .H-fav-fl{height:100%;border-radius:2px;background:linear-gradient(90deg,var(--p2),var(--p));width:0%;transition:width .6s,background .5s;}
        .H-fav-n{font-size:.54rem;color:var(--a);font-weight:700;white-space:nowrap;}
        [data-theme="frost"] .H-fav-n{color:var(--p2);}

        .H-exp-row{display:flex;align-items:center;gap:5px;margin-top:3px;}
        .H-exp-lbl{font-size:.54rem;color:var(--m);white-space:nowrap;letter-spacing:.5px;font-weight:600;}
        .H-exp-tr{flex-grow:1;height:3px;background:rgba(128,128,128,.12);border-radius:2px;overflow:hidden;}
        .H-exp-fl{height:100%;border-radius:2px;background:linear-gradient(90deg,#f59e0b,#ef4444);width:0%;transition:width .7s cubic-bezier(.4,0,.2,1),background .5s;}
        .H-exp-n{font-size:.54rem;color:var(--a);font-weight:700;white-space:nowrap;min-width:28px;text-align:right;}
        [data-theme="frost"] .H-exp-n{color:var(--p2);}

        .H-dots{display:flex;gap:3px;flex-shrink:0;order:10;width:100%;justify-content:center;padding-top:4px;border-top:1px solid var(--bd);}
        .H-d{width:11px;height:11px;border-radius:50%;cursor:pointer;border:1.5px solid rgba(128,128,128,.2);transition:transform .25s,border-color .25s,box-shadow .25s;}
        .H-d:hover{transform:scale(1.3);}
        .H-d.on{border-color:var(--p);box-shadow:0 0 6px var(--g);}
        .H-d[data-t="void"]{background:#c084fc;}
        .H-d[data-t="cyber"]{background:#00d4ff;}
        .H-d[data-t="emerald"]{background:#50c878;}
        .H-d[data-t="frost"]{background:linear-gradient(135deg,#e2e8f0,#f8fafc);border-color:rgba(148,163,184,.3);}
        .H-d[data-t="obsidian"]{background:linear-gradient(135deg,#1f2937,#374151);border-color:rgba(75,85,99,.3);}
        .H-d[data-t="crimson"]{background:#ef4444;}

        /* ========== BODY (single column for mobile) ========== */
        .B{display:flex;flex-direction:column;position:relative;z-index:1;}

        /* ---- 折叠面板按钮 ---- */
        .panel-toggle{display:flex;justify-content:center;gap:4px;padding:6px 0;background:var(--c2);border-bottom:1px solid var(--bd);cursor:pointer;transition:background .3s;}
