        .panel-toggle-label{font-size:.6rem;color:var(--m);font-weight:600;letter-spacing:1px;}
        .panel-toggle i{font-size:.55rem;color:var(--p);transition:transform .3s;}
        .panel-toggle.collapsed i{transform:rotate(180deg);}

        /* ---- 各面板区块 ---- */
