        .S{font-size:.62rem;color:var(--m);text-transform:uppercase;letter-spacing:2px;margin:0 0 6px;display:flex;align-items:center;gap:5px;transition:color .5s;font-weight:700;}
        .S i{color:var(--p);font-size:.62rem;transition:color .5s;}
