        [data-theme="frost"] .AT-v{color:var(--t);}
        .AT-bar{height:3px;background:rgba(128,128,128,.1);border-radius:2px;margin-top:4px;overflow:hidden;}
        .AT-fill{height:100%;border-radius:2px;transition:width .7s,background .5s;}
        .AT-fill.f-str{background:var(--p);}.AT-fill.f-agi{background:var(--a);}
        [data-theme="frost"] .AT-fill.f-agi{background:var(--p2);}
        .AT-fill.f-con{background:var(--p2);}.AT-fill.f-spi{background:var(--m);}
        .AT-add{display:none;position:absolute;top:4px;right:4px;background:var(--a);color:var(--btn-t);border-radius:50%;width:14px;height:14px;text-align:center;line-height:14px;font-size:.62rem;font-weight:900;cursor:pointer;box-shadow:0 0 4px var(--g2);transition:transform .2s,background .5s;}
        .AT-add:hover{transform:scale(1.15);}
