        /* ---- 内心想法（修复：限制高度+可滚动） ---- */
        .MY{margin-top:8px;padding:6px 8px;background:var(--c2);border-radius:10px;border-left:3px solid var(--a);transition:all .5s;max-height:120px;overflow-y:auto;}
        [data-theme="frost"] .MY{border-left-color:var(--p2);}
        .MY-lbl{font-size:.5rem;color:var(--m);text-transform:uppercase;letter-spacing:1px;font-weight:600;}
