        .NPC-th{margin-top:5px;font-size:.68rem;color:var(--t2);font-style:italic;opacity:.85;padding-left:6px;border-left:2px solid var(--bd);transition:all .5s;line-height:1.35;max-height:80px;overflow-y:auto;word-break:break-word;overflow-wrap:break-word;}
        .NPC-th::-webkit-scrollbar{width:3px;}
        .NPC-th::-webkit-scrollbar-track{background:transparent;}
        .NPC-th::-webkit-scrollbar-thumb{background:var(--bd);border-radius:2px;}

        /* ---- 召唤物（修复：确保始终有正确的显示逻辑） ---- */
        .SM{display:none;}
        .SM.show{display:block;}
        .SM-list{display:flex;flex-direction:column;gap:5px;}
        .SM-card{background:var(--c2);border-radius:10px;padding:7px 10px;border:1px solid var(--bd);transition:all .3s;}
        .SM-card:hover{border-color:var(--p);}
        .SM-top{display:flex;justify-content:space-between;align-items:center;}
        .SM-name{font-size:.76rem;font-weight:700;color:var(--a);}
        [data-theme="frost"] .SM-name{color:var(--p2);}
        .SM-tag{font-size:.52rem;color:var(--p);background:var(--c1);padding:1px 5px;border-radius:5px;font-weight:600;}
        .SM-stats{display:flex;gap:8px;margin-top:3px;font-size:.6rem;color:var(--m);font-weight:600;flex-wrap:wrap;}
        .SM-stats span{color:var(--t2);}
        .SM-desc{font-size:.58rem;color:var(--m);font-style:italic;margin-top:3px;}
        .SM-btn{font-size:.55rem;padding:2px 8px;border-radius:6px;cursor:pointer;background:var(--p);color:var(--btn-t);font-weight:700;border:none;transition:opacity .2s,transform .2s;margin-top:4px;display:inline-block;}
        .SM-btn:hover{opacity:.8;transform:scale(1.03);}

        /* ---- 背包 ---- */
        .BAG{display:flex;flex-wrap:wrap;gap:4px;}
        .BAG-i{font-size:.68rem;padding:3px 8px;border-radius:8px;background:var(--c2);display:flex;align-items:center;gap:3px;border:1px solid rgba(128,128,128,.06);transition:all .3s;cursor:default;font-weight:500;}
        .BAG-i:hover{border-color:var(--bd);}
        .BAG-ic{color:var(--p);font-size:.64rem;transition:color .5s;}
        .BAG-c{color:var(--a);font-size:.58rem;font-weight:700;transition:color .5s;}
        [data-theme="frost"] .BAG-c{color:var(--p2);}
        .BAG-use{font-size:.5rem;padding:1px 5px;border-radius:5px;cursor:pointer;background:var(--p);color:var(--btn-t);font-weight:700;border:none;margin-left:3px;transition:opacity .2s,transform .2s;line-height:1.5;}
        .BAG-use:hover{opacity:.8;transform:scale(1.06);}

        /* ---- 底部信息栏 ---- */
        .F{display:flex;flex-wrap:wrap;gap:5px 8px;padding:8px 12px;border-top:1px solid var(--bd);font-size:.64rem;color:var(--m);position:relative;z-index:1;background:var(--c2);transition:all .5s;font-weight:600;}
        .F-i{display:flex;align-items:center;gap:3px;}
        .F-i i{color:var(--p);font-size:.6rem;transition:color .5s;}
        .F-v{color:var(--t2);transition:color .5s;}
        .F-q{color:var(--a);font-weight:700;transition:color .5s;}
        [data-theme="frost"] .F-q{color:var(--p2);}
        .F-full{width:100%;}

        /* ---- PC宽屏适配 ---- */
        @media (min-width:601px){
            body{padding:10px;}
            .W{border-radius:16px;}
            .H{padding:14px 18px;gap:12px;flex-wrap:nowrap;}
            .H-ava{width:52px;height:52px;border-radius:14px;}
            .H-name{font-size:1.1rem;}
            .H-lv{font-size:.68rem;padding:1px 8px;}
            .H-job{font-size:.76rem;}
            .H-state{font-size:.72rem;padding:1px 7px;}
            .H-pts{font-size:.7rem;padding:2px 8px;}
            .H-fav-row{gap:6px;margin-top:4px;}
            .H-fav-lbl{font-size:.6rem;}
            .H-fav-tr{height:4px;}
            .H-fav-n{font-size:.6rem;}
            .H-exp-row{gap:6px;margin-top:4px;}
            .H-exp-lbl{font-size:.6rem;}
            .H-exp-tr{height:4px;}
            .H-exp-n{font-size:.6rem;}
            .H-dots{gap:4px;order:0;width:auto;justify-content:flex-end;padding-top:0;border-top:none;}
            .H-d{width:13px;height:13px;}
            .B{display:grid;grid-template-columns:1fr 1fr;grid-template-rows:auto;}
            .B-section{padding:14px 16px;}
            .B-section.B-left{grid-column:1;border-right:1px solid var(--bd);border-bottom:none;}
            .B-section.B-right{grid-column:2;border-bottom:none;}
            .panel-toggle{display:none;}
            .S{font-size:.68rem;margin:0 0 8px;}
            .S i{font-size:.7rem;}
            .AT{gap:8px;}
            .AT-i{padding:10px;}
            .AT-nm{font-size:.66rem;}
            .AT-v{font-size:1.5rem;}
            .AT-bar{height:4px;margin-top:5px;}
            .AT-add{width:16px;height:16px;line-height:16px;font-size:.72rem;top:5px;right:5px;}
            .MY{margin-top:10px;padding:8px 10px;max-height:160px;}
            .MY-lbl{font-size:.58rem;}
            .MY-txt{font-size:.78rem;margin-top:3px;line-height:1.45;}
            .SK-n{font-size:.82rem;}
            .SK-l{font-size:.58rem;padding:1px 6px;}
            .SK-d{font-size:.7rem;line-height:1.4;padding:5px 8px;}
            .SK-i details{padding:6px 0;}
            .NPC{padding:10px 12px;}
            .NPC-n{font-size:.92rem;}
            .NPC-inf{font-size:.68rem;}
            .NPC-state{font-size:.65rem;}
            .NPC-th{font-size:.75rem;padding-left:8px;line-height:1.4;max-height:100px;}
            .FAV{gap:6px;margin-top:6px;}
            .FAV-tr{height:5px;}
