            .F-i{gap:4px;}
            .F-i i{font-size:.68rem;}
        }
    </style>

    <script>
    (function(){
        function applyTheme(t){
            var w=document.querySelector('.W');
            if(!w)return;
            w.setAttribute('data-theme',t);var dots=document.querySelectorAll('.H-d');
            for(var i=0;i<dots.length;i++){
                if(dots[i].getAttribute('data-t')===t){dots[i].classList.add('on');}
                else{dots[i].classList.remove('on');}
            }try{localStorage.setItem('qqgw_theme',t);}catch(e){}
        }

        function toggleCollapse(){
            var w=document.querySelector('.W');
            if(!w)return;
            var sections=w.querySelectorAll('.B-section'),f=w.querySelector('.F'),tog=w.querySelector('.panel-toggle');
            if(!sections.length||!f)return;
            var isHidden=sections[0].style.display==='none';
            for(var i=0;i<sections.length;i++){
                sections[i].style.display=isHidden?'':'none';
            }
            f.style.display=isHidden?'':'none';
            if(tog){
                if(isHidden){tog.classList.remove('collapsed');}
                else{tog.classList.add('collapsed');}
            }
        }

        function sendCmd(text){
            try{
                var el=parent.document.getElementById('send_textarea');
                if(el){var v=el.value||'';el.value=v+(v&&!v.endsWith('\n')?'\n':'')+text;el.focus();el.dispatchEvent(new Event('input',{bubbles:true}));}
            }catch(e){}
        }

        function bindAll(){
            var saved='void';
            try{saved=localStorage.getItem('qqgw_theme')||'void';}catch(e){}
            applyTheme(saved);

            document.addEventListener('click',function(e){
                var dot=e.target.closest?e.target.closest('.H-d'):null;
                if(!dot&&e.target.classList&&e.target.classList.contains('H-d'))dot=e.target;
                if(dot){var t=dot.getAttribute('data-t');if(t)applyTheme(t);return;}

                var ava=e.target.closest?e.target.closest('.H-ava'):null;
                if(!ava&&e.target.classList&&e.target.classList.contains('H-ava'))ava=e.target;
                if(ava){toggleCollapse();return;}

                var togBtn=e.target.closest?e.target.closest('.panel-toggle'):null;
                if(togBtn){toggleCollapse();return;}

                var add=e.target.closest?e.target.closest('.AT-add'):null;
                if(!add&&e.target.classList&&e.target.classList.contains('AT-add'))add=e.target;
                if(add){
                    var stat=add.getAttribute('data-stat');
                    if(stat)sendCmd('（系统指令：消耗1点未分配属性点，提升【'+stat+'】。请描写属性提升感受并输出变量更新）');
                    return;
                }

                var use=e.target.closest?e.target.closest('.BAG-use'):null;
                if(!use&&e.target.classList&&e.target.classList.contains('BAG-use'))use=e.target;
                if(use){
                    var item=use.getAttribute('data-item');
                    if(item)sendCmd('（系统指令：我使用了背包中的【'+item+'】。请描写使用效果，扣除该物品数量1个（数量为0则移除），并输出变量更新）');
                    return;
                }

                var sm=e.target.closest?e.target.closest('.SM-btn'):null;
                if(!sm&&e.target.classList&&e.target.classList.contains('SM-btn'))sm=e.target;
                if(sm){
                    var nm=sm.getAttribute('data-summon');
                    if(nm)sendCmd('（系统指令：我对召唤物/契约体【'+nm+'】下达指令。请描写它的行动并输出变量更新）');
                    return;
                }
            });
        }

        if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',bindAll);}
        else{bindAll();}
    })();
    </script>

    <script type="module">
        function g(p,d){try{return _.get(getAllVariables(),'stat_data.'+p,d);}catch(e){return d;}}

        function isUsable(name){
            var keys=['药','丹','水','卷轴','符','瓶','食','饮','膏','散','丸','剂','包扎','绷带','解毒','回复','治疗','补给'];
            return keys.some(function(k){return name.includes(k);});
        }

        /* ====== 技能智能更新（修复：保留 details 展开状态） ====== */
        function updateSkills(sk){
            var container=document.querySelector('.SK');
            if(!container)return;

            if(_.isEmpty(sk)){
                container.innerHTML='<div style="font-size:.72rem;color:var(--m);opacity:.6;font-style:italic;">尚未觉醒任何技能</div>';
                return;
            }

            // 记录当前哪些技能的 details 是展开的
            var openSet={};
            container.querySelectorAll('.SK-i details[open]').forEach(function(det){
                var nameEl=det.querySelector('.SK-n');
                if(nameEl)openSet[nameEl.textContent]=true;
            });

            // 收集当前已有的技能名 → DOM 映射
            var existingMap={};
            container.querySelectorAll('.SK-i').forEach(function(item){
                var nameEl=item.querySelector('.SK-n');
                if(nameEl)existingMap[nameEl.textContent]=item;
            });

            // 删除面板上有但数据里已经没有的技能
            Object.keys(existingMap).forEach(function(name){
                if(!sk.hasOwnProperty(name)){
                    existingMap[name].remove();
                    delete existingMap[name];
                }
            });

            // 删除那个空提示（如果之前是空的）
            var emptyHint=container.querySelector('div[style]');
            if(emptyHint&&emptyHint.textContent.includes('尚未觉醒'))emptyHint.remove();

            // 遍历数据，更新或添加
            _.forEach(sk,function(v,k){
                if(!v)return;
                var l=typeof v==='object'?(v.等级||1):1;
                var d=typeof v==='object'?(v.描述||'暂无描述'):v;

                if(existingMap[k]){
                    // 已存在 → 只更新文字，不重建DOM，保留open状态
                    var item=existingMap[k];
                    var lvEl=item.querySelector('.SK-l');
                    if(lvEl)lvEl.textContent='Lv.'+l;
                    var descEl=item.querySelector('.SK-d');
                    if(descEl)descEl.textContent=d;
                }else{
                    // 新技能 → 创建DOM
                    var div=document.createElement('div');
                    div.className='SK-i';
                    var isOpen=openSet[k]?'open':'';
                    div.innerHTML='<details '+isOpen+'><summary><span class="SK-n">'+k+'</span><span style="display:flex;align-items:center;gap:3px;"><span class="SK-l">Lv.'+l+'</span><i class="fa-solid fa-chevron-right SK-arrow"></i></span></summary><div class="SK-d">'+d+'</div></details>';
                    container.appendChild(div);
                }
            });

            // 恢复之前展开的状态（针对已存在的技能）
            container.querySelectorAll('.SK-i').forEach(function(item){
                var nameEl=item.querySelector('.SK-n');
                if(nameEl&&openSet[nameEl.textContent]){
                    var det=item.querySelector('details');
                    if(det)det.setAttribute('open','');
                }
            });
        }

        /* ====== 召唤物更新（修复：确保正确渲染） ====== */
        function updateSummons(summons){
            var smSection=document.querySelector('.SM');
            var smList=document.querySelector('.SM-list');
            if(!smSection||!smList)return;

            if(!summons||_.isEmpty(summons)){
                smSection.classList.remove('show');
                smList.innerHTML='';
                return;
            }

            var smh='';
            if(_.isArray(summons)){
                summons.forEach(function(s){
                    if(!s)return;
                    var nm=s.名称||s.name||'未知',lv=s.等级||s.level||'?',tp=s.类型||s.type||'',hp=s.生命||s.hp||'',atk=s.攻击||s.attack||'',desc=s.描述||s.desc||'',state=s.状态||s.state||'待命';
                    smh+='<div class="SM-card"><div class="SM-top"><span class="SM-name">'+nm+'</span><span class="SM-tag">Lv.'+lv+' '+tp+'</span></div>';
                    if(hp||atk)smh+='<div class="SM-stats">'+(hp?'HP:<span>'+hp+'</span> ':'')+(atk?'ATK:<span>'+atk+'</span> ':'')+'状态:<span>'+state+'</span></div>';
                    if(desc)smh+='<div class="SM-desc">'+desc+'</div>';
                    smh+='<button class="SM-btn" data-summon="'+nm+'">指令</button></div>';
                });
            }else{
                _.forEach(summons,function(v,k){
                    if(!v)return;
                    // 处理值为空对象 {} 的情况
                    if(typeof v==='object'&&_.isEmpty(v))return;
                    var lv=typeof v==='object'?(v.等级||'?'):'?',tp=typeof v==='object'?(v.类型||''):'',hp=typeof v==='object'?(v.生命||''):'',atk=typeof v==='object'?(v.攻击||''):'',desc=typeof v==='object'?(v.描述||''):v,state=typeof v==='object'?(v.状态||'待命'):'待命';
                    smh+='<div class="SM-card"><div class="SM-top"><span class="SM-name">'+k+'</span><span class="SM-tag">Lv.'+lv+' '+tp+'</span></div>';
                    if(hp||atk)smh+='<div class="SM-stats">'+(hp?'HP:<span>'+hp+'</span> ':'')+(atk?'ATK:<span>'+atk+'</span> ':'')+'状态:<span>'+state+'</span></div>';
                    if(desc)smh+='<div class="SM-desc">'+desc+'</div>';
                    smh+='<button class="SM-btn" data-summon="'+k+'">指令</button></div>';
                });
            }

            if(smh){
                smList.innerHTML=smh;
                smSection.classList.add('show');
            }else{
                smSection.classList.remove('show');
                smList.innerHTML='';
            }
        }

        function r(){
            try{
                $('.H-name').text(g('user.姓名','{{user}}'));
                $('.H-lv').text('Lv.'+g('user.等级',1));
                $('.H-job').text(g('user.职业','未觉醒'));
                $('.H-state').text(g('user.当前状态','正常'));
                var pts=Number(g('user.未分配属性点',0))||0;$('.H-pts-v').text(pts);
                if(pts>0){$('.AT-add').css('display','block');$('.H-pts').show();}
                else{$('.AT-add').css('display','none');$('.H-pts').hide();}

                var ufav=Number(g('user.好感度',0))||0;
                $('.H-fav-fl').css('width',Math.min(Math.max(ufav,-100),100)/100*50+50+'%');
                $('.H-fav-n').text(ufav);

                var exp=Number(g('user.当前经验值',0))||0;
                exp=Math.min(Math.max(exp,0),100);
                $('.H-exp-fl').css('width',exp+'%');
                $('.H-exp-n').text(exp+'%');

                var st={str:g('user.力量',0),agi:g('user.敏捷',0),con:g('user.体质',0),spi:g('user.精神',0)};
                $.each(st,function(k,v){$('.v-'+k).text(v);$('.f-'+k).css('width',Math.min(v/200*100,100)+'%');});

                $('.MY-txt').text(g('user.内心想法','...'));

                // 技能：使用智能更新，保留展开状态
                var sk=g('user.技能',{});
                updateSkills(sk);

                $('.NPC-n').text(g('当前角色.姓名','无'));
                $('.NPC-inf').text('Lv.'+g('当前角色.等级','?')+' '+g('当前角色.职业',''));
                $('.NPC-state').text(g('当前角色.当前状态',''));
                $('.NPC-th').text('"'+g('当前角色.内心想法','...')+'"');
                var fav=g('当前角色.好感度',0);
                $('.FAV-fl').css('width',Math.min(Math.max(fav,0),100)+'%');$('.FAV-n').text(fav+'/100');

                // 召唤物：使用修复后的更新函数
                var summons=g('user.召唤物',null)||g('user.契约体',null)||g('user.随从',null);
                updateSummons(summons);

                var bag=g('user.背包',{});var bh='';
                if(_.isEmpty(bag)){bh='<span style="font-size:.7rem;color:var(--m);opacity:.6;font-style:italic;">空空如也</span>';}
                else{_.forEach(bag,function(v,k){
                    var cntHtml=_.isNumber(v)?'<span class="BAG-c">×'+v+'</span>':'';
                    var i='fa-cube';
                    if(k.includes('剑')||k.includes('刀')||k.includes('枪')||k.includes('弓'))i='fa-khanda';
                    else if(k.includes('药')||k.includes('丹')||k.includes('瓶')||k.includes('剂'))i='fa-flask';
                    else if(k.includes('卷轴')||k.includes('书')||k.includes('符'))i='fa-scroll';
                    else if(k.includes('甲')||k.includes('衣')||k.includes('夹克')||k.includes('外套'))i='fa-shirt';
                    else if(k.includes('盾')||k.includes('护'))i='fa-shield-halved';
                    else if(k.includes('戒')||k.includes('链')||k.includes('环'))i='fa-ring';
                    else if(k.includes('食')||k.includes('面包')||k.includes('肉'))i='fa-drumstick-bite';
                    else if(k.includes('钥匙')||k.includes('钥'))i='fa-key';
                    else if(k.includes('金币')||k.includes('钱')||k.includes('币'))i='fa-coins';
                    else if(k.includes('地图'))i='fa-map';
                    var useBtn=isUsable(k)?'<button class="BAG-use" data-item="'+k+'">使用</button>':'';
                    bh+='<div class="BAG-i"><i class="fa-solid '+i+' BAG-ic"></i>'+k+cntHtml+useBtn+'</div>';
                });}
                $('.BAG').html(bh);

                $('.F-loc').text(g('user.当前地点','未知'));
                $('.F-time').text(g('世界.当前时间','--:--'));
                $('.F-weather').text(g('世界.当前天气','--'));
                $('.F-area').text(g('世界.城市区域','--'));
                $('.F-quest').text(g('user.当前任务','无'));
            }catch(e){console.error("R:",e);}
        }

        async function init(){
            await waitGlobalInitialized('Mvu');
            r();
            if(window._ri)clearInterval(window._ri);
            window._ri=setInterval(r,1500);
        }
        $(errorCatched(init));
    </script>
</head>
