        border-radius: 5px;
        cursor: pointer;
        border: 1px solid transparent;
        transition: all 0.2s ease;
    }
    .theme-btn.active {
        border-color: #a7d9ff;
        box-shadow: 0 0 5px #a7d9ff;
    }
    .theme-btn.dark-blue {
        background: #4a69bd;
        color: white;
    }
    .theme-btn.forest-green {
        background: #689f38;
        color: white;
    }
  </style>
</head>
<body>
  <div id="mvu-status-panel" class="mvu-container theme-dark-blue">
    <div class="header" id="user-name-header"></div>

    <div class="section">
      <div class="section-title">玩家状态</div>
      <div class="info-item"><span class="info-label">等级:</span><span class="info-value" id="user-level"></span></div>
      <div class="info-item"><span class="info-label">职业:</span><span class="info-value" id="user-job"></span></div>
      <div class="info-item"><span class="info-label">地点:</span><span class="info-value" id="user-location"></span></div>
      <div class="info-item"><span class="info-label">任务:</span><span class="info-value" id="user-task"></span></div>
      <div class="info-item"><span class="info-label">内心:</span><span class="info-value" id="user-thoughts"></span></div>
      <div class="info-item"><span class="info-label">经验:</span><span class="info-value" id="user-exp"></span></div>
      <div class="progress-bar"><div class="progress-bar-fill" id="exp-progress"></div></div>
      <div class="info-item"><span class="info-label">饥饿:</span><span class="info-value" id="user-hunger"></span></div>
      <div class="progress-bar"><div class="progress-bar-fill" id="hunger-progress"></div></div>
      <div class="info-item"><span class="info-label">心情:</span><span class="info-value" id="user-mood"></span></div>
      <div class="progress-bar"><div class="progress-bar-fill" id="mood-progress"></div></div>
      <div class="info-item"><span class="info-label">异常状态:</span><span class="info-value" id="user-abnormal-status"></span></div>
    </div>

    <div class="section">
      <div class="section-title">
        <span>属性</span>
        <span id="unallocated-points-display">
          <span class="info-label">未分配:</span> <span class="info-value" id="user-unallocated">0</span>
          <button class="add-btn" id="add-attr-btn" style="display: none;">+</button>
        </span>
      </div>
      <div class="attr-grid">
        <div class="attr-item"><span class="attr-label">力量:</span><span class="attr-value" id="user-str"></span></div>
        <div class="attr-item"><span class="attr-label">敏捷:</span><span class="attr-value" id="user-dex"></span></div>
        <div class="attr-item"><span class="attr-label">体质:</span><span class="attr-value" id="user-con"></span></div>
        <div class="attr-item"><span class="attr-label">精神:</span><span class="attr-value" id="user-int"></span></div>
      </div>
    </div>

    <div class="section">
      <div class="section-title">当前NPC: <span id="current-npc-name"></span></div>
      <div class="info-item"><span class="info-label">职业:</span><span class="info-value" id="current-npc-job"></span></div>
      <div class="info-item"><span class="info-label">状态:</span><span class="info-value" id="current-npc-status"></span></div>
      <div class="info-item"><span class="info-label">内心:</span><span class="info-value" id="current-npc-thoughts"></span></div>
      <div class="info-item"><span class="info-label">好感度:</span><span class="info-value" id="current-npc-affection-value"></span></div>
      <div class="progress-bar"><div class="progress-bar-fill" id="current-npc-affection-progress"></div></div>
    </div>

    <div class="section">
      <div class="section-title">
        <span>养成追踪</span>
        <span class="info-label">阶段: <span class="info-value" id="track-stage"></span></span>
      </div>
      <div class="info-item"><span class="info-label">完成度:</span><span class="info-value" id="track-completion-value"></span></div>
      <div class="progress-bar"><div class="progress-bar-fill" id="track-completion-progress"></div></div>
      <div class="info-item"><span class="info-label">信任度:</span><span class="info-value" id="track-trust-value"></span></div>
      <div class="progress-bar"><div class="progress-bar-fill" id="track-trust-progress"></div></div>
      <div class="info-item"><span class="info-label">心理防线:</span><span class="info-value" id="track-defense-value"></span></div>
      <div class="progress-bar"><div class="progress-bar-fill" id="track-defense-progress"></div></div>
      <div class="section-title">部位开发</div>
      <div id="track-body-development" class="attr-grid"></div>
    </div>

    <div class="section">
      <div class="section-title">技能</div>
      <div id="user-skills" class="list-container"></div>
    </div>

    <div class="section">
      <div class="section-title">
        <span>背包</span>
        <span><span class="info-label">货币:</span> <span class="info-value" id="system-currency"></span></span>
      </div>
      <div id="user-bag" class="list-container"></div>
      <button class="btn" id="shop-btn">打开商店</button>
    </div>

    <div class="section">
        <div class="section-title">世界</div>
        <div class="info-item"><span class="info-label">时间:</span><span class="info-value" id="world-time"></span></div>
        <div class="info-item"><span class="info-label">天气:</span><span class="info-value" id="world-weather"></span></div>
        <div class="info-item"><span class="info-label">区域:</span><span class="info-value" id="world-area"></span></div>
    </div>

    <div class="theme-switcher">
        <button class="theme-btn dark-blue active" data-theme="dark-blue">深蓝</button>
        <button class="theme-btn forest-green" data-theme="forest-green">森林绿</button>
    </div>
  </div>

  <!-- Shop Modal -->
  <div id="shop-modal" class="shop-modal">
    <div class="shop-modal-content">
      <span class="close-btn" id="close-shop-modal">&times;</span>
      <h3>商店</h3>
      <div class="info-item" style="margin-bottom: 10px;"><span class="info-label">你的货币:</span> <span class="info-value" id="shop-currency-display"></span></div>
      <div id="shop-items-list"></div>
    </div>
  </div>

<script type="module">
  function r() {
    try {
      var data = getAllVariables().stat_data;

      // User Info
      var userName = _.get(data, "user.姓名", "{{user}}");
      var userLevel = _.get(data, "user.等级", 1);
      var userExp = _.get(data, "user.当前经验值", 0);
      var userJob = _.get(data, "user.职业", "未知");
      var userLocation = _.get(data, "user.当前地点", "某地");
      var userTask = _.get(data, "user.当前任务", "无");
      var userThoughts = _.get(data, "user.内心想法", "无");
      var unallocatedPoints = _.get(data, "user.未分配属性点", 0);

      $("#user-name-header").text(userName);
      $("#user-level").text(userLevel);
      $("#user-job").text(userJob);
      $("#user-location").text(userLocation);
      $("#user-task").text(userTask);
      $("#user-thoughts").text(userThoughts);
      $("#user-exp").text(`${userExp}/100`);
      $("#exp-progress").css("width", `${userExp}%`);
      $("#user-unallocated").text(unallocatedPoints);
      $("#add-attr-btn").toggle(unallocatedPoints > 0);

      // User Attributes
      $("#user-str").html(`${_.get(data, "user.力量", 50)}`);
      $("#user-dex").html(`${_.get(data, "user.敏捷", 50)}`);
      $("#user-con").html(`${_.get(data, "user.体质", 50)}`);
      $("#user-int").html(`${_.get(data, "user.精神", 50)}`);

      // User Status (Hunger, Mood, Abnormal)
      var userHunger = _.get(data, "user.状态.饥饿", 100);
      var userMood = _.get(data, "user.状态.心情", 100);
      var abnormalStatus = _.get(data, "user.状态.异常状态", {});
      let abnormalStatusText = Object.keys(abnormalStatus).map(key => `${key}: ${abnormalStatus[key]}`).join(", ");
      if (!abnormalStatusText) abnormalStatusText = "无";

      $("#user-hunger").text(`${userHunger}/100`);
      $("#hunger-progress").css("width", `${userHunger}%`);
      $("#user-mood").text(`${userMood}/100`);
      $("#mood-progress").css("width", `${userMood}%`);
      $("#user-abnormal-status").text(abnormalStatusText);

      // Current NPC Info
      var npcName = _.get(data, "当前角色.姓名", "未知NPC");
      var npcLevel = _.get(data, "当前角色.等级", 1);
      var npcJob = _.get(data, "当前角色.职业", "未知职业");
      var npcStatus = _.get(data, "当前角色.当前状态", "正常");
      var npcThoughts = _.get(data, "当前角色.内心想法", "无");
      var npcAffections = _.get(data, "当前角色.好感度", 0);

      $("#current-npc-name").text(npcName);
      $("#current-npc-job").text(npcJob);
      $("#current-npc-status").text(npcStatus);
      $("#current-npc-thoughts").text(npcThoughts);
      $("#current-npc-affection-value").text(npcAffections);
      // Affection progress bar: -100 to 100, 0 is 50%
      let affectionWidth = (npcAffections + 100) / 2; // Scale to 0-100
      $("#current-npc-affection-progress").css("width", `${affectionWidth}%`);

      // World Info
      $("#world-time").text(_.get(data, "世界.当前时间", "未知时间"));
      $("#world-weather").text(_.get(data, "世界.当前天气", "未知天气"));
      $("#world-area").text(_.get(data, "世界.城市区域", "未知区域"));

      // Skills
      var skills = _.get(data, "user.技能", {});
      let skillsHtml = "";
      if (_.isEmpty(skills)) {
        skillsHtml = "<div class='list-item info-label'>暂无技能</div>";
      } else {
        _.forEach(skills, function(v, k) {
          var slv = _.get(v, "等级", 1);
          var desc = _.get(v, "描述", "");
          skillsHtml += `<div class='list-item'><span class='info-value'>${k} Lv.${slv}</span> <span class='info-label'>(${desc})</span></div>`;
        });
      }
      $("#user-skills").html(skillsHtml);

      // Bag & Currency
      var bag = _.get(data, "user.背包", {});
      var currency = _.get(data, "系统.货币", 0);
      let bagHtml = "";
      if (_.isEmpty(bag)) {
        bagHtml = "<div class='list-item info-label'>背包空空如也</div>";
      } else {
        _.forEach(bag, function(count, itemName) {
          bagHtml += `<div class='list-item'><span class='info-value'>${itemName}</span> <span class='info-label'>x${count}</span></div>`;
        });
      }
      $("#user-bag").html(bagHtml);
      $("#system-currency").text(currency);
      $("#shop-currency-display").text(currency); // Update shop currency display

      // Shop Items
      var shopItems = _.get(data, "系统.商品列表", {});
      let shopItemsHtml = "";
      if (_.isEmpty(shopItems)) {
        shopItemsHtml = "<div class='info-label'>商店暂无商品</div>";
      } else {
        _.forEach(shopItems, function(item, itemName) {
            const canAfford = currency >= item.价格;
            const isPurchasedPermanent = item.类型 === '永久道具' && item.已购买;
            const disabledAttr = (!canAfford || isPurchasedPermanent) ? 'disabled' : '';
            const buttonText = isPurchasedPermanent ? '已购买' : '购买';

            shopItemsHtml += `
                <div class='shop-item'>
                    <div class='shop-item-info'>
                        <div class='shop-item-name'>${itemName}</div>
                        <div class='shop-item-desc'>${item.描述} (${item.类型})</div>
                    </div>
                    <div class='shop-item-price'>${item.价格} 货币</div>
                    <button class='shop-item-buy-btn' data-item-name="${itemName}" ${disabledAttr}>${buttonText}</button>
                </div>
            `;
        });
      }
      $("#shop-items-list").html(shopItemsHtml);


      // Nurturing/Tracking System (养成追踪)
      var trackCompletion = _.get(data, "养成追踪.完成度", 0);
      var trackStage = _.get(data, "养成追踪.阶段", 1);
      var trackTrust = _.get(data, "养成追踪.信任度", 0);
      var trackDefense = _.get(data, "养成追踪.心理防线", 100);
      var trackBodyDev = _.get(data, "养成追踪.部位开发", {});

      $("#track-completion-value").text(`${trackCompletion}/100`);
      $("#track-completion-progress").css("width", `${trackCompletion}%`);
      $("#track-stage").text(trackStage);
      $("#track-trust-value").text(`${trackTrust}/100`);
      $("#track-trust-progress").css("width", `${trackTrust}%`);
      $("#track-defense-value").text(`${trackDefense}/100`);
      $("#track-defense-progress").css("width", `${trackDefense}%`);

      let bodyDevHtml = "";
      if (_.isEmpty(trackBodyDev)) {
        bodyDevHtml = "<div class='info-label'>暂无部位开发追踪</div>";
      } else {
        _.forEach(trackBodyDev, function(devValue, partName) {
          bodyDevHtml += `
            <div class='attr-item'>
                <span class='attr-label'>${partName}:</span>
                <span class='attr-value'>${devValue}/100</span>
            </div>
          `;
        });
      }
      $("#track-body-development").html(bodyDevHtml);

    } catch(e) { console.error("MVU UI Error:", e); }
  }

  // Function to update a variable
  async function updateVariable(path, value) {
      if (typeof updateMvuVariable === 'function') {
          await updateMvuVariable(path, value);
          r(); // Refresh UI after update
      } else {
          console.error("updateMvuVariable function not available.");
      }
  }

  // Shop Button Logic
  $(document).on('click', '#shop-btn', function() {
      $('#shop-modal').css('display', 'flex'); // Show modal
      r(); // Refresh shop contents
  });

  $(document).on('click', '#close-shop-modal', function() {
      $('#shop-modal').css('display', 'none'); // Hide modal
  });

  // Close modal when clicking outside of it
  $(window).on('click', function(event) {
      if ($(event.target).is('#shop-modal')) {
          $('#shop-modal').css('display', 'none');
      }
  });

  // Buy Item Logic
  $(document).on('click', '.shop-item-buy-btn', async function() {
      const itemName = $(this).data('item-name');
      const data = getAllVariables().stat_data;
      const item = _.get(data, `系统.商品列表.${itemName}`);
      const currentCurrency = _.get(data, "系统.货币", 0);

      if (!item) {
          console.error("Item not found:", itemName);
          return;
      }
      if (currentCurrency < item.价格) {
          toastr.warning("货币不足！");
          return;
      }
      if (item.类型 === '永久道具' && item.已购买) {
          toastr.info("此永久道具已购买。");
          return;
      }

      // Deduct currency
      await updateVariable("系统.货币", currentCurrency - item.价格);

      // Handle item type
      if (item.类型 === '消耗品') {
          const currentCount = _.get(data, `user.背包.${itemName}`, 0);
          await updateVariable(`user.背包.${itemName}`, currentCount + 1);
          toastr.success(`购买了 ${itemName} x1`);
      } else if (item.类型 === '永久道具') {
          await updateVariable(`系统.商品列表.${itemName}.已购买`, true);
          await updateVariable(`系统.道具状态.${itemName}`, true); // Mark as active/owned in道具状态
          toastr.success(`购买了永久道具 ${itemName}！`);
      } else if (item.类型 === '装备') {
          const currentCount = _.get(data, `user.背包.${itemName}`, 0);
          await updateVariable(`user.背包.${itemName}`, currentCount + 1);
          toastr.success(`购买了装备 ${itemName} x1`);
      }
      r(); // Refresh UI
  });

  // Attribute Add Button Logic (Placeholder for actual logic)
  $(document).on('click', '#add-attr-btn', function() {
      toastr.info("点击属性值进行分配。此功能需要后端逻辑支持。");
      // Example: If you want to distribute to STR
      // updateVariable("user.力量", _.get(data, "user.力量", 50) + 1);
      // updateVariable("user.未分配属性点", unallocatedPoints - 1);
  });

  // Theme Switching
  $(document).on('click', '.theme-btn', function() {
      const theme = $(this).data('theme');
      $('#mvu-status-panel').removeClass('theme-dark-blue theme-forest-green').addClass(`theme-${theme}`);
      $('.theme-btn').removeClass('active');
      $(this).addClass('active');
  });


  async function init() {
    await waitGlobalInitialized("Mvu");
    r();
    if(window._ri) clearInterval(window._ri);
    window._ri = setInterval(r, 1500);
  }
  $(errorCatched(init));
<\/script>
</body>
